     5→fn resolve_states(state_filter: &str) -> Vec<&str> {
     6→    match state_filter {
     7→        "all" => vec!["drafts", "pending", "running", "done", "failed", "merged"],
     8→        "active" => vec!["pending", "running", "done"],
     9→        "drafts" => vec!["drafts"],
    10→        other => vec![other],
    11→    }
    12→}
