    14→pub fn list_cards(root: &Path, state_filter: &str) -> anyhow::Result<()> {
    15→    let states = resolve_states(state_filter);
    16→
    17→    for state in &states {
    18→        print_state_group(root, state, None)?;
    19→
    20→        // Also check team-* directories
    21→        if let Ok(entries) = fs::read_dir(root) {
    22→            let mut team_dirs: Vec<_> = entries
    23→                .flatten()
    24→                .filter(|e| {
    25→                    let name = e.file_name();
    26→                    let s = name.to_string_lossy();
    27→                    e.path().is_dir() && s.starts_with("team-")
    28→                })
    29→                .collect();
    30→            team_dirs.sort_by_key(|e| e.file_name());
    31→            for entry in team_dirs {
    32→                print_state_group(
    33→                    &entry.path(),
    34→                    state,
    35→                    Some(&entry.file_name().to_string_lossy()),
    36→                )?;
    37→            }
    38→        }
    39→    }
    40→    Ok(())
    41→}
