   107→pub fn list_cards_json(
   108→    root: &Path,
   109→    state_filter: &str,
   110→    out: &mut impl Write,
   111→) -> anyhow::Result<()> {
   112→    let states = resolve_states(state_filter);
   113→
   114→    for state in &states {
   115→        emit_state_json(root, state, None, out)?;
   116→
   117→        if let Ok(entries) = fs::read_dir(root) {
   118→            let mut team_dirs: Vec<_> = entries
   119→                .flatten()
   120→                .filter(|e| {
   121→                    let name = e.file_name();
   122→                    let s = name.to_string_lossy();
   123→                    e.path().is_dir() && s.starts_with("team-")
   124→                })
   125→                .collect();
   126→            team_dirs.sort_by_key(|e| e.file_name());
   127→            for entry in team_dirs {
   128→                emit_state_json(
   129→                    &entry.path(),
   130→                    state,
   131→                    Some(entry.file_name().to_string_lossy().into_owned()),
   132→                    out,
   133→                )?;
   134→            }
   135→        }
   136→    }
   137→    Ok(())
   138→}
   139→
   140→fn emit_state_json(
   141→    dir: &Path,
   142→    state: &str,
   143→    team: Option<String>,
   144→    out: &mut impl Write,
   145→) -> anyhow::Result<()> {
   146→    let state_dir = dir.join(state);
   147→    if !state_dir.exists() {
   148→        return Ok(());
   149→    }
   150→
   151→    if let Ok(entries) = fs::read_dir(&state_dir) {
   152→        let mut metas: Vec<bop_core::Meta> = entries
   153→            .flatten()
   154→            .filter(|e| {
   155→                e.path().is_dir()
   156→                    && e.path()
   157→                        .extension()
   158→                        .is_some_and(|x| x == "bop" || x == "jobcard")
   159→            })
   160→            .filter_map(|e| bop_core::read_meta(&e.path()).ok())
   161→            .collect();
   162→        metas.sort_by(|a, b| a.id.cmp(&b.id));
   163→
   164→        for meta in &metas {
   165→            let card = JsonCard {
   166→                state,
   167→                team: team.clone(),
   168→                meta,
   169→            };
   170→            writeln!(out, "{}", serde_json::to_string(&card)?)?;
   171→        }
   172→    }
   173→    Ok(())
   174→}
