    20→fn state_color(state: &str) -> &'static str {
    21→    match state {
    22→        "pending" => "#3A5A8A",
    23→        "running" => "#B8690F",
    24→        "done" => "#1E8A45",
    25→        "failed" => "#C43030",
    26→        "merged" => "#6B3DB8",
    27→        _ => "#555",
    28→    }
