    31→fn parse_ts(s: &str) -> Option<DateTime<Utc>> {
    32→    // Try standard ISO, then strip Z and retry
    33→    if let Ok(dt) = s.parse::<DateTime<Utc>>() {
    34→        return Some(dt);
    35→    }
    36→    // chrono's parse with flexible format
    37→    chrono::NaiveDateTime::parse_from_str(s.trim_end_matches('Z'), "%Y-%m-%dT%H:%M:%S")
    38→        .ok()
    39→        .map(|n| n.and_utc())
    40→}
    41→
    42→fn collect_bars(root: &Path) -> Vec<Bar> {
    43→    let states = ["running", "done", "merged", "failed", "pending"];
    44→    let mut bars = Vec::new();
    45→
    46→    for state in &states {
    47→        let dir = root.join(state);
    48→        if !dir.exists() {
    49→            continue;
    50→        }
    51→        let Ok(entries) = fs::read_dir(&dir) else {
    52→            continue;
    53→        };
    54→        for entry in entries.flatten() {
    55→            let path = entry.path();
    56→            if path.extension().and_then(|e| e.to_str()) != Some("bop") {
    57→                continue;
    58→            }
    59→            let Ok(meta) = bop_core::read_meta(&path) else {
    60→                continue;
    61→            };
    62→            let Some(last_run) = meta.runs.last() else {
    63→                continue;
    64→            };
    65→            let Some(start) = parse_ts(&last_run.started_at) else {
    66→                continue;
    67→            };
    68→
    69→            let end = last_run
    70→                .ended_at
    71→                .as_deref()
    72→                .and_then(parse_ts)
    73→                .unwrap_or_else(|| {
    74→                    // Cap open-ended: use duration_s or 10 min
    75→                    let dur = last_run.duration_s.unwrap_or(0) as i64;
    76→                    if dur > 0 {
    77→                        start + Duration::seconds(dur)
    78→                    } else {
    79→                        start + Duration::minutes(10)
    80→                    }
    81→                });
    82→
    83→            let dur_s = (end - start).num_milliseconds() as f64 / 1000.0;
    84→            if dur_s < 2.0 {
    85→                continue;
    86→            }
    87→
    88→            let tokens = match (last_run.prompt_tokens, last_run.completion_tokens) {
    89→                (Some(p), Some(c)) => Some(p + c),
    90→                (Some(p), None) => Some(p),
    91→                (None, Some(c)) => Some(c),
    92→                _ => None,
    93→            };
    94→
    95→            bars.push(Bar {
    96→                id: meta.id.clone(),
    97→                glyph: meta.glyph.or(meta.token).unwrap_or_default(),
    98→                state: state.to_string(),
    99→                stage: meta.stage.clone(),
   100→                provider: last_run.provider.clone(),
   101→                start,
   102→                end,
   103→                dur_s,
   104→                tokens,
   105→                cost: last_run.cost_usd,
   106→            });
   107→        }
   108→    }
   109→
   110→    bars.sort_by_key(|b| b.start);
   111→    bars
   112→}
   113→
   114→/// Cluster bars: gap > 30 min = new cluster.
   115→fn cluster(bars: &[Bar]) -> Vec<Vec<usize>> {
   116→    if bars.is_empty() {
   117→        return Vec::new();
   118→    }
   119→    let mut clusters: Vec<Vec<usize>> = vec![vec![0]];
   120→    for i in 1..bars.len() {
   121→        let prev_end = bars[clusters.last().unwrap().iter().copied().fold(0, |best, j| {
   122→            if bars[j].end > bars[best].end {
   123→                j
   124→            } else {
   125→                best
   126→            }
   127→        })]
   128→        .end;
   129→        if (bars[i].start - prev_end).num_seconds() > 1800 {
   130→            clusters.push(vec![i]);
   131→        } else {
   132→            clusters.last_mut().unwrap().push(i);
   133→        }
   134→    }
   135→    clusters
   136→}
