   148→/// ANSI 256-color codes for each state.
   149→fn state_ansi(state: &str) -> &'static str {
   150→    match state {
   151→        "pending" => "\x1b[38;5;67m",  // steel blue
   152→        "running" => "\x1b[38;5;172m", // amber
   153→        "done" => "\x1b[38;5;71m",     // green
   154→        "failed" => "\x1b[38;5;160m",  // red
   155→        "merged" => "\x1b[38;5;134m",  // violet
   156→        _ => "\x1b[38;5;240m",         // gray
   157→    }
   158→}
   159→
   160→/// ANSI background block for bar fill.
   161→fn state_ansi_bg(state: &str) -> &'static str {
   162→    match state {
   163→        "pending" => "\x1b[48;5;67m",
   164→        "running" => "\x1b[48;5;172m",
   165→        "done" => "\x1b[48;5;71m",
   166→        "failed" => "\x1b[48;5;160m",
   167→        "merged" => "\x1b[48;5;134m",
   168→        _ => "\x1b[48;5;240m",
   169→    }
   170→}
