   176→fn render_ansi(bars: &[Bar], term_width: usize) {
   177→    let clusters = cluster(bars);
   178→    let label_width = 24_usize;
   179→    let dur_width = 7_usize;
   180→    // bar_cols = total width - label - " │ " (3) - " " (1) - dur_label - " " (1)
   181→    let bar_cols = term_width
   182→        .saturating_sub(label_width + 3 + dur_width + 2)
   183→        .max(20);
   184→
   185→    // Header
   186→    println!(
   187→        "{}bop · agent timeline{} {} — {} runs{}",
   188→        BOLD,
   189→        RESET,
   190→        DIM,
   191→        bars.len(),
   192→        RESET
   193→    );
   194→    println!();
   195→
   196→    for indices in &clusters {
   197→        let c_min = indices.iter().map(|&i| bars[i].start).min().unwrap();
   198→        let c_max = indices.iter().map(|&i| bars[i].end).max().unwrap();
   199→        let c_span = (c_max - c_min).num_seconds().max(1) as f64;
   200→
   201→        // Cluster header
   202→        println!(
   203→            "{}{} — {} · {} runs{}",
   204→            DIM,
   205→            c_min.format("%b %d, %H:%M"),
   206→            c_max.format("%H:%M"),
   207→            indices.len(),
   208→            RESET,
   209→        );
   210→
   211→        // Time axis
   212→        let mut axis = String::with_capacity(label_width + 3 + bar_cols);
   213→        for _ in 0..label_width {
   214→            axis.push(' ');
   215→        }
   216→        axis.push_str(" │ ");
   217→
   218→        // Place time labels on the axis
   219→        let mut axis_chars: Vec<char> = vec![' '; bar_cols];
   220→        // We'll place a few evenly-spaced time markers
   221→        let n_marks = (bar_cols / 15).clamp(2, 8);
   222→        for m in 0..n_marks {
   223→            let frac = m as f64 / (n_marks - 1).max(1) as f64;
   224→            let col = (frac * (bar_cols - 5) as f64) as usize;
   225→            let t = c_min + Duration::milliseconds((frac * c_span * 1000.0) as i64);
   226→            let label = t.format("%H:%M").to_string();
   227→            for (j, ch) in label.chars().enumerate() {
   228→                if col + j < bar_cols {
   229→                    axis_chars[col + j] = ch;
   230→                }
   231→            }
   232→        }
   233→        let axis_str: String = axis_chars.into_iter().collect();
   234→        println!("{}{}{}{}", axis, DIM, axis_str, RESET);
   235→
   236→        // Separator
   237→        let mut sep = String::with_capacity(label_width + 3 + bar_cols);
   238→        for _ in 0..label_width {
   239→            sep.push(' ');
   240→        }
   241→        sep.push_str(" ├─");
   242→        for _ in 0..bar_cols {
   243→            sep.push('─');
   244→        }
   245→        println!("{}{}{}", DIM, sep, RESET);
   246→
   247→        // Bars
   248→        for &i in indices {
   249→            let b = &bars[i];
   250→
   251→            // Label: glyph + truncated id
