    45→pub fn print_state_group(dir: &Path, state: &str, team_prefix: Option<&str>) -> anyhow::Result<()> {
    46→    let state_dir = dir.join(state);
    47→    if !state_dir.exists() {
    48→        return Ok(());
    49→    }
    50→
    51→    let mut cards: Vec<bop_core::Meta> = Vec::new();
    52→    if let Ok(entries) = fs::read_dir(&state_dir) {
    53→        for entry in entries.flatten() {
    54→            let p = entry.path();
    55→            if p.is_dir() && p.extension().is_some_and(|e| e == "bop" || e == "jobcard") {
    56→                if let Ok(meta) = bop_core::read_meta(&p) {
    57→                    cards.push(meta);
    58→                }
    59→            }
    60→        }
    61→    }
    62→
    63→    let header = match team_prefix {
    64→        Some(team) => format!("{}/{}", team, state),
    65→        None => state.to_string(),
    66→    };
    67→
    68→    println!("{} ({})", header, cards.len());
    69→    for meta in &cards {
    70→        let glyph = meta.glyph.as_deref().unwrap_or("  ");
    71→        let token = meta.token.as_deref().unwrap_or(" ");
    72→        let id_display = if meta.id.len() > 32 {
    73→            &meta.id[..32]
    74→        } else {
    75→            &meta.id
    76→        };
    77→        let pri = meta
    78→            .priority
    79→            .map(|p| format!("P{}", p))
    80→            .unwrap_or_else(|| "--".into());
    81→        let pct = meta.progress.unwrap_or(0);
    82→        let filled = (pct as usize * 8) / 100;
    83→        let bar: String = (0..8)
    84→            .map(|i| if i < filled { '\u{2588}' } else { '\u{2591}' })
    85→            .collect();
    86→        let pct_str = if pct > 0 {
    87→            format!("{}%", pct)
    88→        } else {
    89→            String::new()
    90→        };
    91→        println!(
    92→            "  {} {}  {:<32}  {:<12} {:<3} {} {}",
    93→            glyph, token, id_display, meta.stage, pri, bar, pct_str
    94→        );
    95→    }
    96→    println!();
    97→    Ok(())
    98→}
