   137→pub fn print_state_group(dir: &Path, state: &str, team_prefix: Option<&str>) -> anyhow::Result<()> {
   138→    let state_dir = dir.join(state);
   139→    if !state_dir.exists() {
   140→        return Ok(());
   141→    }
