   143→    let mut cards: Vec<bop_core::Meta> = Vec::new();
   144→    if let Ok(entries) = fs::read_dir(&state_dir) {
   145→        for entry in entries.flatten() {
   146→            let p = entry.path();
   147→            if p.is_dir() && p.extension().is_some_and(|e| e == "bop" || e == "jobcard") {
   148→                if let Ok(meta) = bop_core::read_meta(&p) {
   149→                    cards.push(meta);
   150→                }
   151→            }
   152→        }
   153→    }
   154→
   155→    let header = match team_prefix {
   156→        Some(team) => format!("{}/{}", team, state),
   157→        None => state.to_string(),
   158→    };
   159→
   160→    println!(
   161→        "{}● {}{} ({})",
   162→        state_ansi(state),
   163→        header,
   164→        RESET,
   165→        cards.len()
   166→    );
   167→    for meta in &cards {
   168→        let glyph = meta.glyph.as_deref().unwrap_or("  ");
   169→        let token = meta.token.as_deref().unwrap_or(" ");
   170→        let id_display = if meta.id.len() > 32 {
   171→            &meta.id[..32]
   172→        } else {
   173→            &meta.id
   174→        };
   175→        let pri = meta
   176→            .priority
   177→            .map(|p| format!("P{}", p))
