   180→        let filled = (pct as usize * 8) / 100;
   181→        let bar: String = (0..8)
   182→            .map(|i| if i < filled { '\u{2588}' } else { '\u{2591}' })
   183→            .collect();
   184→        let pct_str = if pct > 0 {
