   142→/// Format duration in human-readable form (e.g., "4m32s" or "45s").
   143→fn format_duration(seconds: f64) -> String {
   144→    if seconds >= 60.0 {
   145→        let mins = (seconds / 60.0).floor() as u64;
   146→        let secs = (seconds % 60.0).round() as u64;
   147→        if secs > 0 {
   148→            format!("{}m{}s", mins, secs)
   149→        } else {
   150→            format!("{}m", mins)
   151→        }
   152→    } else {
   153→        format!("{}s", seconds.round() as u64)
   154→    }
   155→}
   156→
   157→/// Display summary statistics line.
   158→fn print_summary(stats: &CardStats) {
   159→    let mut parts = vec![format!("{} total", stats.total)];
   160→
   161→    // Add key state counts
   162→    for state in ["running", "done", "failed", "pending"] {
   163→        if let Some(&count) = stats.by_state.get(state) {
   164→            if count > 0 {
   165→                parts.push(format!("{} {}", count, state));
   166→            }
   167→        }
   168→    }
   169→
   170→    // Add average duration if available
   171→    if let Some(avg) = stats.avg_duration_s {
   172→        parts.push(format!("avg {}", format_duration(avg)));
   173→    }
   174→
   175→    println!("{}", parts.join(" · "));
   176→}
