    17→/// Summary statistics for cards in the workspace.
    18→pub struct CardStats {
    19→    pub total: usize,
    20→    pub by_state: HashMap<String, usize>,
    21→    pub avg_duration_s: Option<f64>,
    22→    pub success_rate_pct: Option<f64>,
    23→}
    24→
    25→/// Calculate statistics: count cards by state and compute average duration.
    26→pub fn calculate_stats(root: &Path) -> anyhow::Result<CardStats> {
    27→    let states = ["drafts", "pending", "running", "done", "failed", "merged"];
    28→    let mut by_state = HashMap::new();
    29→    let mut total = 0;
    30→    let mut durations = Vec::new();
    31→
    32→    for state in &states {
    33→        // Process root-level state directory
    34→        collect_state_stats(root, state, &mut by_state, &mut total, &mut durations)?;
    35→
    36→        // Process team-* directories
    37→        if let Ok(entries) = fs::read_dir(root) {
    38→            for entry in entries.flatten() {
    39→                let team_path = entry.path();
    40→                if team_path.is_dir()
    41→                    && entry.file_name().to_string_lossy().starts_with("team-")
    42→                {
    43→                    collect_state_stats(
    44→                        &team_path,
    45→                        state,
    46→                        &mut by_state,
    47→                        &mut total,
    48→                        &mut durations,
    49→                    )?;
    50→                }
    51→            }
    52→        }
    53→    }
    54→
    55→    let avg_duration_s = if durations.is_empty() {
    56→        None
    57→    } else {
    58→        Some(durations.iter().sum::<f64>() / durations.len() as f64)
    59→    };
    60→
    61→    let success_rate_pct = {
    62→        let done = by_state.get("done").copied().unwrap_or(0);
    63→        let failed = by_state.get("failed").copied().unwrap_or(0);
    64→        if done + failed > 0 {
    65→            Some((done as f64 / (done + failed) as f64) * 100.0)
    66→        } else {
    67→            None
    68→        }
    69→    };
    70→
    71→    Ok(CardStats {
    72→        total,
    73→        by_state,
    74→        avg_duration_s,
    75→        success_rate_pct,
    76→    })
    77→}
    78→
    79→fn collect_state_stats(
    80→    dir: &Path,
    81→    state: &str,
    82→    by_state: &mut HashMap<String, usize>,
    83→    total: &mut usize,
    84→    durations: &mut Vec<f64>,
    85→) -> anyhow::Result<()> {
    86→    let state_dir = dir.join(state);
    87→    if !state_dir.exists() {
    88→        return Ok(());
    89→    }
    90→
    91→    let Ok(entries) = fs::read_dir(&state_dir) else {
    92→        return Ok(());
    93→    };
    94→
    95→    for entry in entries.flatten() {
    96→        let path = entry.path();
    97→        if path.is_dir() && path.extension().is_some_and(|e| e == "bop" || e == "jobcard") {
    98→            if let Ok(meta) = bop_core::read_meta(&path) {
    99→                *by_state.entry(state.to_string()).or_insert(0) += 1;
   100→                *total += 1;
   101→
   102→                // Collect duration from last run if available
   103→                if let Some(last_run) = meta.runs.last() {
   104→                    if let Some(dur) = last_run.duration_s {
   105→                        durations.push(dur as f64);
   106→                    }
   107→                }
   108→            }
   109→        }
   110→    }
   111→
   112→    Ok(())
   113→}
