   104→pub fn find_card(root: &Path, id: &str) -> Option<PathBuf> {
   105→    let suffix = format!("-{}.bop", id);
   106→    let exact = format!("{}.bop", id);
   107→    for dir in ["drafts", "pending", "running", "done", "merged", "failed"] {
   108→        let state_dir = root.join(dir);
   109→        // Exact match (legacy / no-glyph prefix)
   110→        let p = state_dir.join(&exact);
   111→        if p.exists() {
   112→            return Some(p);
   113→        }
   114→        // Glyph-prefixed match: {glyph}-{id}.bop
   115→        if let Ok(entries) = fs::read_dir(&state_dir) {
   116→            for entry in entries.flatten() {
   117→                let path = entry.path();
   118→                if path.is_dir()
   119→                    && path
   120→                        .file_name()
   121→                        .and_then(|n| n.to_str())
   122→                        .map(|n| n.ends_with(&suffix))
   123→                        .unwrap_or(false)
   124→                {
   125→                    return Some(path);
   126→                }
   127→            }
   128→        }
   129→    }
   130→    None
   131→}
