    81→/// Copy a single file using APFS COW clone when possible.
    82→/// On macOS this requires `cp -c`; on other OSes it falls back to regular copy.
    83→pub fn cow_copy_file(src: &Path, dst: &Path) -> anyhow::Result<()> {
    84→    if cfg!(target_os = "macos") {
    85→        let status = StdCommand::new("cp")
    86→            .arg("-c") // APFS clone
    87→            .arg(src)
    88→            .arg(dst)
    89→            .status();
    90→        if matches!(status, Ok(s) if s.success()) {
    91→            return Ok(());
    92→        }
    93→        anyhow::bail!(
    94→            "APFS COW copy failed (required on macOS): {} -> {}",
    95→            src.display(),
    96→            dst.display()
    97→        );
    98→    }
    99→    fs::copy(src, dst)
   100→        .with_context(|| format!("failed to copy {} -> {}", src.display(), dst.display()))?;
   101→    Ok(())
   102→}
