    fn calculate_stats_empty_workspace() {
        let td = tempdir().unwrap();
        let stats = calculate_stats(td.path()).unwrap();
        assert_eq!(stats.total, 0);
        assert!(stats.by_state.is_empty());
        assert!(stats.avg_duration_s.is_none());
