        fs::create_dir_all(&card_dir).unwrap();
        let meta = bop_core::Meta {
            id: id.into(),
            stage: "implement".into(),
            runs: vec![bop_core::RunRecord {
                duration_s: Some(duration_s),
                ..Default::default()
            }],
            ..Default::default()
        };
        bop_core::write_meta(&card_dir, &meta).unwrap();
    }

